import { GoogleGenAI } from '@google/genai';
import React, { useState, useCallback, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';

import { AuditSession, AuditCategory } from './types';
import { KRITERIA_5R, INITIAL_PLACEHOLDERS } from './constants';
import { generateId } from './utils';

import DottedGlowBackground from './components/DottedGlowBackground';
import SideDrawer from './components/SideDrawer';
import RadarChart from './components/RadarChart';
import { 
    ThinkingIcon, 
    SparklesIcon, 
    ArrowUpIcon, 
    GridIcon,
    CodeIcon
} from './components/Icons';

function App() {
  const [view, setView] = useState<'welcome' | 'form' | 'results'>('welcome');
  const [auditorName, setAuditorName] = useState('');
  const [auditArea, setAuditArea] = useState('');
  const [currentStep, setCurrentStep] = useState(0);
  const [scores, setScores] = useState<Record<string, number[]>>({});
  const [sessions, setSessions] = useState<AuditSession[]>([]);
  const [currentSession, setCurrentSession] = useState<AuditSession | null>(null);

  const [isLoading, setIsLoading] = useState(false);
  const [drawerOpen, setDrawerOpen] = useState(false);

  const startAudit = () => {
    if (!auditorName || !auditArea) return;
    const initialScores: Record<string, number[]> = {};
    KRITERIA_5R.forEach(cat => {
        initialScores[cat.name] = cat.questions.map(() => 3);
    });
    setScores(initialScores);
    setView('form');
    setCurrentStep(0);
  };

  const handleScoreChange = (category: string, questionIndex: number, value: number) => {
    setScores(prev => ({
        ...prev,
        [category]: prev[category].map((s, i) => i === questionIndex ? value : s)
    }));
  };

  const calculateResults = async () => {
    setIsLoading(true);
    const categoryAverages: Record<string, number> = {};
    let totalSum = 0;

    KRITERIA_5R.forEach(cat => {
        const avg = scores[cat.name].reduce((a, b) => a + b, 0) / cat.questions.length;
        categoryAverages[cat.name] = avg;
        totalSum += avg;
    });

    const totalAverage = totalSum / KRITERIA_5R.length;

    const newSession: AuditSession = {
        id: generateId(),
        auditor: auditorName,
        area: auditArea,
        date: new Date().toLocaleDateString(),
        scores: scores,
        averages: categoryAverages,
        totalAverage: totalAverage,
        timestamp: Date.now()
    };

    setCurrentSession(newSession);
    setView('results');

    // Generate AI Insights
    try {
        const apiKey = process.env.API_KEY;
        if (!apiKey) return;
        const ai = new GoogleGenAI({ apiKey });

        const prompt = `
Analyze these 5R Audit results for the area: "${auditArea}".
Auditor: ${auditorName}
Scores (1-5 scale):
${Object.entries(categoryAverages).map(([k, v]) => `- ${k}: ${v.toFixed(2)}`).join('\n')}

**Task:**
1. Provide a concise overall summary of the warehouse's 5R health.
2. Identify the weakest "R" and suggest 3 specific Kaizen (continuous improvement) actions to fix it.
3. Highlight one strength found.
4. Keep the tone professional, encouraging, and actionable.
Format as clean Markdown.
        `.trim();

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: [{ role: 'user', parts: [{ text: prompt }] }]
        });

        const insights = response.text || "Unable to generate insights at this time.";
        const updatedSession = { ...newSession, aiInsights: insights };
        setCurrentSession(updatedSession);
        setSessions(prev => [updatedSession, ...prev]);
    } catch (e) {
        console.error("AI Insights failed", e);
    } finally {
        setIsLoading(false);
    }
  };

  const downloadReport = () => {
    if (!currentSession) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(currentSession, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href",     dataStr);
    downloadAnchorNode.setAttribute("download", `audit_${currentSession.area}_${currentSession.date}.json`);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <>
        <div className="immersive-app">
            <DottedGlowBackground 
                gap={24} 
                radius={1.5} 
                color="rgba(255, 255, 255, 0.02)" 
                glowColor="rgba(255, 255, 255, 0.1)" 
                speedScale={0.3} 
            />

            {view === 'welcome' && (
                <div className="audit-stage center-flex">
                    <div className="hero-content">
                        <div className="badge">5R COMPLIANCE</div>
                        <h1>5R Internal Audit</h1>
                        <p>Warehouse RM Technical & FG Herbisida</p>

                        <div className="audit-setup-card">
                            <div className="input-group">
                                <label>Auditor Name</label>
                                <input 
                                    type="text" 
                                    placeholder="Enter your name" 
                                    value={auditorName} 
                                    onChange={(e) => setAuditorName(e.target.value)}
                                />
                            </div>
                            <div className="input-group">
                                <label>Audit Area</label>
                                <select value={auditArea} onChange={(e) => setAuditArea(e.target.value)}>
                                    <option value="">Select Area...</option>
                                    <option value="WH RM Technical">WH RM Technical</option>
                                    <option value="FG Herbisida">FG Herbisida</option>
                                    <option value="Office">Office</option>
                                </select>
                            </div>
                            <button 
                                className="primary-button" 
                                onClick={startAudit}
                                disabled={!auditorName || !auditArea}
                            >
                                Start New Audit
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {view === 'form' && (
                <div className="audit-stage">
                    <div className="form-wizard">
                        <div className="wizard-header">
                            <div className="step-indicator">
                                {KRITERIA_5R.map((cat, i) => (
                                    <div 
                                        key={cat.name} 
                                        className={`step-dot ${i === currentStep ? 'active' : ''} ${i < currentStep ? 'done' : ''}`}
                                    />
                                ))}
                            </div>
                            <h2>{KRITERIA_5R[currentStep].name}</h2>
                            <p>Score each item from 1 (Poor) to 5 (Excellent)</p>
                        </div>

                        <div className="question-list">
                            {KRITERIA_5R[currentStep].questions.map((q, idx) => (
                                <div key={idx} className="question-item">
                                    <div className="question-text">{q}</div>
                                    <div className="score-selector">
                                        {[1, 2, 3, 4, 5].map(v => (
                                            <button 
                                                key={v}
                                                className={`score-btn ${scores[KRITERIA_5R[currentStep].name][idx] === v ? 'selected' : ''}`}
                                                onClick={() => handleScoreChange(KRITERIA_5R[currentStep].name, idx, v)}
                                            >
                                                {v}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>

                        <div className="wizard-footer">
                            <button 
                                className="secondary-button"
                                disabled={currentStep === 0}
                                onClick={() => setCurrentStep(prev => prev - 1)}
                            >
                                Previous
                            </button>
                            {currentStep < KRITERIA_5R.length - 1 ? (
                                <button 
                                    className="primary-button"
                                    onClick={() => setCurrentStep(prev => prev + 1)}
                                >
                                    Next Category
                                </button>
                            ) : (
                                <button 
                                    className="primary-button finish-btn"
                                    onClick={calculateResults}
                                >
                                    Submit Audit
                                </button>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {view === 'results' && currentSession && (
                <div className="audit-stage results-view">
                    <div className="results-grid">
                        <div className="results-main">
                            <div className="results-header">
                                <div className="summary-info">
                                    <h1>Audit Report</h1>
                                    <p>{currentSession.area} • {currentSession.date}</p>
                                </div>
                                <div className="total-score-box">
                                    <span className="score-val">{currentSession.totalAverage.toFixed(2)}</span>
                                    <span className="score-label">Average Score</span>
                                </div>
                            </div>

                            <div className="ai-insights-container">
                                <div className="section-title">
                                    <SparklesIcon /> AI Smart Insights
                                </div>
                                {isLoading ? (
                                    <div className="ai-loading">
                                        <ThinkingIcon /> Analyzing performance patterns...
                                    </div>
                                ) : (
                                    <div className="ai-content markdown">
                                        {currentSession.aiInsights}
                                    </div>
                                )}
                            </div>

                            <div className="actions-footer">
                                <button className="outline-button" onClick={() => setView('welcome')}>
                                    <ArrowUpIcon style={{transform: 'rotate(-90deg)'}} /> New Audit
                                </button>
                                <button className="outline-button" onClick={downloadReport}>
                                    <CodeIcon /> Export JSON
                                </button>
                                <button className="outline-button" onClick={() => setDrawerOpen(true)}>
                                    <GridIcon /> History
                                </button>
                            </div>
                        </div>

                        <div className="results-sidebar">
                            <div className="radar-container">
                                <h3>Performance Visual</h3>
                                <RadarChart 
                                    data={Object.entries(currentSession.averages).map(([k, v]) => ({ label: k, value: v }))} 
                                    size={340}
                                />
                            </div>

                            <div className="score-breakdown">
                                <h3>Breakdown</h3>
                                {Object.entries(currentSession.averages).map(([cat, val]) => (
                                    <div key={cat} className="breakdown-item">
                                        <div className="breakdown-label">
                                            <span>{cat}</span>
                                            <span>{val.toFixed(1)}/5.0</span>
                                        </div>
                                        <div className="progress-bg">
                                            <div className="progress-fill" style={{ width: `${(val / 5) * 100}%` }} />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>

        <SideDrawer 
            isOpen={drawerOpen} 
            onClose={() => setDrawerOpen(false)} 
            title="Audit History"
        >
            <div className="history-list">
                {sessions.length === 0 ? (
                    <div className="empty-history">No past audits recorded.</div>
                ) : (
                    sessions.map(s => (
                        <div key={s.id} className="history-card" onClick={() => { setCurrentSession(s); setDrawerOpen(false); }}>
                            <div className="h-header">
                                <strong>{s.area}</strong>
                                <span>{s.totalAverage.toFixed(2)}</span>
                            </div>
                            <div className="h-meta">{s.date} • {s.auditor}</div>
                        </div>
                    ))
                )}
            </div>
        </SideDrawer>
    </>
  );
}

const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(<React.StrictMode><App /></React.StrictMode>);
}

/* index.css - 5R Internal Audit Immersive Theme */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Roboto+Mono&display=swap');

:root {
    --app-bg: #09090b;
    --text-primary: #ffffff;
    --text-secondary: #a1a1aa;
    --accent: #ffffff;
    --card-bg: rgba(24, 24, 27, 0.7);
    --border: rgba(255, 255, 255, 0.1);
    --primary: #ffffff;
    --primary-hover: #e4e4e7;
}

body, html {
    margin: 0; padding: 0;
    font-family: 'Inter', sans-serif;
    background: var(--app-bg);
    color: var(--text-primary);
    overflow: hidden;
    height: 100%;
}

#root { height: 100%; }

.immersive-app {
    position: relative;
    width: 100vw; height: 100vh;
    display: flex; flex-direction: column;
}

.center-flex { display: flex; align-items: center; justify-content: center; }

.audit-stage {
    flex: 1; z-index: 10;
    padding: 40px;
    display: flex; flex-direction: column;
    overflow-y: auto;
}

/* Welcome Screen */
.hero-content {
    text-align: center; max-width: 500px;
}
.badge {
    display: inline-block; padding: 4px 12px; border-radius: 99px;
    background: rgba(255,255,255,0.1); color: var(--text-secondary);
    font-size: 0.7rem; font-weight: 700; letter-spacing: 0.1em;
    margin-bottom: 16px; border: 1px solid var(--border);
}
.hero-content h1 { font-size: 3.5rem; font-weight: 800; margin: 0; letter-spacing: -0.03em; }
.hero-content p { color: var(--text-secondary); font-size: 1.1rem; margin-top: 8px; }

.audit-setup-card {
    margin-top: 40px; background: var(--card-bg);
    padding: 32px; border-radius: 24px; border: 1px solid var(--border);
    backdrop-filter: blur(20px); text-align: left;
    display: flex; flex-direction: column; gap: 20px;
    box-shadow: 0 20px 40px rgba(0,0,0,0.4);
}

.input-group { display: flex; flex-direction: column; gap: 8px; }
.input-group label { font-size: 0.85rem; font-weight: 600; color: var(--text-secondary); }
.input-group input, .input-group select {
    background: rgba(0,0,0,0.3); border: 1px solid var(--border);
    padding: 12px 16px; border-radius: 12px; color: white;
    font-size: 1rem; outline: none; transition: all 0.2s;
}
.input-group input:focus { border-color: white; }

.primary-button {
    background: white; color: black; border: none; padding: 16px;
    border-radius: 12px; font-weight: 700; cursor: pointer;
    transition: all 0.2s; font-size: 1rem;
}
.primary-button:hover:not(:disabled) { transform: translateY(-2px); opacity: 0.9; }
.primary-button:disabled { opacity: 0.3; cursor: not-allowed; }

/* Form Wizard */
.form-wizard {
    max-width: 700px; margin: 0 auto; width: 100%;
    background: var(--card-bg); border: 1px solid var(--border);
    border-radius: 32px; padding: 40px; backdrop-filter: blur(20px);
}
.wizard-header { text-align: center; margin-bottom: 40px; }
.step-indicator { display: flex; justify-content: center; gap: 12px; margin-bottom: 24px; }
.step-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--border); transition: 0.3s; }
.step-dot.active { width: 24px; border-radius: 4px; background: white; }
.step-dot.done { background: rgba(255,255,255,0.4); }

.question-list { display: flex; flex-direction: column; gap: 24px; margin-bottom: 40px; }
.question-item { 
    padding-bottom: 20px; border-bottom: 1px solid var(--border);
    display: flex; align-items: center; justify-content: space-between; gap: 20px;
}
.question-text { font-weight: 500; color: var(--text-secondary); line-height: 1.4; flex: 1; }
.score-selector { display: flex; gap: 8px; }
.score-btn {
    width: 36px; height: 36px; border-radius: 10px; border: 1px solid var(--border);
    background: transparent; color: white; cursor: pointer; transition: 0.2s;
    font-weight: 600;
}
.score-btn:hover { background: rgba(255,255,255,0.05); }
.score-btn.selected { background: white; color: black; border-color: white; }

.wizard-footer { display: flex; justify-content: space-between; gap: 16px; }
.secondary-button {
    background: rgba(255,255,255,0.05); color: white; border: 1px solid var(--border);
    padding: 12px 24px; border-radius: 12px; cursor: pointer;
}
.finish-btn { background: #4ade80; color: black; }

/* Results View */
.results-view { padding-top: 20px; }
.results-grid {
    display: grid; grid-template-columns: 1fr 400px; gap: 40px;
    max-width: 1200px; margin: 0 auto; width: 100%;
}
.results-header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 40px; }
.total-score-box { text-align: right; }
.score-val { font-size: 4rem; font-weight: 800; display: block; line-height: 1; }
.score-label { font-size: 0.8rem; text-transform: uppercase; color: var(--text-secondary); letter-spacing: 0.1em; }

.ai-insights-container {
    background: rgba(255,255,255,0.03); border: 1px solid var(--border);
    border-radius: 24px; padding: 32px; margin-bottom: 40px;
}
.section-title { font-weight: 700; margin-bottom: 20px; display: flex; align-items: center; gap: 8px; }
.ai-loading { display: flex; align-items: center; gap: 12px; color: var(--text-secondary); }
.ai-content { line-height: 1.6; color: rgba(255,255,255,0.85); }
.markdown h1, .markdown h2, .markdown h3 { color: white; margin-top: 1.5em; }
.markdown ul { padding-left: 20px; }

.actions-footer { display: flex; gap: 12px; flex-wrap: wrap; }
.outline-button {
    background: transparent; border: 1px solid var(--border); color: white;
    padding: 10px 20px; border-radius: 12px; cursor: pointer; display: flex; align-items: center; gap: 8px;
    transition: 0.2s; font-size: 0.9rem;
}
.outline-button:hover { background: rgba(255,255,255,0.05); border-color: rgba(255,255,255,0.3); }

.results-sidebar { display: flex; flex-direction: column; gap: 40px; }
.radar-container {
    background: rgba(0,0,0,0.2); border: 1px solid var(--border);
    padding: 24px; border-radius: 24px; display: flex; flex-direction: column; align-items: center;
}
.radar-container h3 { margin: 0 0 20px 0; font-size: 1rem; color: var(--text-secondary); width: 100%; text-align: left; }

.score-breakdown h3 { margin-bottom: 20px; font-size: 1rem; }
.breakdown-item { margin-bottom: 16px; }
.breakdown-label { display: flex; justify-content: space-between; font-size: 0.85rem; margin-bottom: 6px; }
.progress-bg { height: 6px; background: rgba(255,255,255,0.05); border-radius: 3px; overflow: hidden; }
.progress-fill { height: 100%; background: white; border-radius: 3px; }

/* History Drawer */
