.history-card {
    background: rgba(255,255,255,0.03); border: 1px solid var(--border);
    padding: 16px; border-radius: 16px; cursor: pointer; transition: 0.2s;
}
.history-card:hover { transform: translateX(5px); background: rgba(255,255,255,0.06); }
.h-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px; }
.h-meta { font-size: 0.75rem; color: var(--text-secondary); }

/* Animation Overrides */
.spin-icon { animation: spin 1.5s linear infinite; }
@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

.drawer-overlay {
    position: fixed; inset: 0; background: rgba(0,0,0,0.6); backdrop-filter: blur(10px);
